let todayDegree = 14;

if (15 >= todayDegree) {
  console.log("小美會穿著外套出門");
}
// 15 >= 14 是 true

let todayDegree = 20;

if (15 >= todayDegree) {
  console.log("小美會穿著外套出門");
}
// 15 >= 20 是 false，跳過

let temperature = 14;

if (temperature <= 15) {
  console.log("穿外套出門");
} else {
  console.log("穿短袖出門");
}
// 14 <= 15 是 true

let score = 75;

if (score >= 90) {
  console.log("優秀");
} else if (score >= 70) {
  console.log("良好");
} else if (score >= 60) {
  console.log("及格");
} else {
  console.log("不及格");
}
// 75 >= 90？false → 75 >= 70？true

let score = 95;

// 錯誤寫法：寬鬆的放前面
if (score >= 60) {
  console.log("及格");     // 95 >= 60 是 true，到這就停了
} else if (score >= 90) {
  console.log("優秀");     // 永遠不會執行
}

let score = 95;

// 正確寫法：嚴格的放前面
if (score >= 90) {
  console.log("優秀");     // 95 >= 90 是 true
} else if (score >= 60) {
  console.log("及格");
}

let todayWeather = "毛毛雨";

if (todayWeather == "沒有下雨") {
  console.log("小華不帶雨具");
} else if (todayWeather == "毛毛雨") {
  console.log("帶了輕便雨衣");
} else if (todayWeather == "普通的雨") {
  console.log("帶了折傘");
}

let meal = "牛肉麵";

if (meal === "滷肉飯") {
  console.log("50 元");
} else if (meal === "牛肉麵") {
  console.log("120 元");
} else if (meal === "水餃") {
  console.log("80 元");
} else {
  console.log("沒有這個餐點");
}

let age = 8;

if (age < 6 || age >= 65) {
  console.log("免費入場");
} else if (age <= 12) {
  console.log("半票：150 元");
} else {
  console.log("全票：300 元");
}
// 8 < 6？false，8 >= 65？false → 8 <= 12？true

// 題目：BMI 健康判斷
// 第一步：列出情況
// BMI < 18.5 → 過輕
// BMI 18.5~23.9 → 正常
// BMI 24~26.9 → 過重
// BMI >= 27 → 肥胖

// 第二步：從小到大排序
// 第三步：寫程式碼
let bmi = 22;

if (bmi < 18.5) {
  console.log("過輕");
} else if (bmi < 24) {
  console.log("正常");
} else if (bmi < 27) {
  console.log("過重");
} else {
  console.log("肥胖");
}

// 錯誤 1：漏寫大括號
let score = 80;

if (score >= 60)
  console.log("及格");
  console.log("恭喜你"); // 這行不在 if 裡面，永遠會執行

// 正確寫法：永遠加大括號
if (score >= 60) {
  console.log("及格");
  console.log("恭喜你");
}

// 錯誤 2：用 = 而非 ===
let x = 3;

if (x = 5) {
  console.log("x 等於 5"); // 永遠會執行！
}
console.log(x); // x 被改成 5 了

// = 是賦值，把 5 存進 x
// 5 是 truthy，所以條件永遠成立

// 錯誤 3：順序寫反
let score = 95;

if (score >= 60) {
  console.log("及格"); // 95 >= 60 是 true，到這就停了
} else if (score >= 90) {
  console.log("優秀"); // 永遠執行不到
}

// 錯誤 4：忘記 else 保底
let fruit = "榴槤";

if (fruit === "蘋果") {
  console.log("30 元");
} else if (fruit === "香蕉") {
  console.log("15 元");
}
// 榴槤不在選項中，什麼都不會發生
// 加上 else 就能處理這種情況

